import{_ as t,o as i,c as n,al as a}from"./chunks/framework.BOATtE-F.js";const u=JSON.parse('{"title":"Documentation","description":"","frontmatter":{"title":"Documentation","next":{"text":"Addon Development","link":"/en/posts/docs/addon/index"}},"headers":[],"relativePath":"en/posts/docs/index.md","filePath":"en/posts/docs/index.md","lastUpdated":1773840449000}'),o={name:"en/posts/docs/index.md"};function r(l,e,s,c,d,m){return i(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="development-documentation" tabindex="-1">Development Documentation <a class="header-anchor" href="#development-documentation" aria-label="Permalink to “Development Documentation”">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to “Overview”">​</a></h2><p>The AnvilCraft development documentation provides comprehensive technical guidance for mod developers and content creators, covering all aspects from add-on mod development to data pack customization.</p><h3 id="documentation-structure" tabindex="-1">Documentation Structure <a class="header-anchor" href="#documentation-structure" aria-label="Permalink to “Documentation Structure”">​</a></h3><p>This documentation is divided into four major sections:</p><h4 id="_1-addon-development" tabindex="-1">1. <a href="./addon/">Addon Development</a> <a class="header-anchor" href="#_1-addon-development" aria-label="Permalink to “1. Addon Development”">​</a></h4><p>Guides developers on creating addon mods based on AnvilCraft core, including:</p><ul><li>Environment setup and toolchain configuration</li><li>Item and block creation and registration</li><li>Content management with Registrum/Registrate-style APIs</li><li>NeoForge mod development best practices</li></ul><h4 id="_2-datapack" tabindex="-1">2. <a href="./datapack/">Datapack</a> <a class="header-anchor" href="#_2-datapack" aria-label="Permalink to “2. Datapack”">​</a></h4><p>Covers AnvilCraft datapack systems, now documenting 32 recipe types:</p><ul><li><strong>Core crafting recipes</strong>: item/block compress, crush, unpack</li><li><strong>Special process recipes</strong>: stamping, bulging, squeezing, inject</li><li><strong>Environment interaction recipes</strong>: in-world, cooking, super heating</li><li><strong>Advanced recipes</strong>: time warp, multiblock, mob transform</li><li><strong>Decorative recipes</strong>: jewel crafting, mineral fountain, block smear</li><li><strong>Extended mechanisms</strong>: mesh, boiling, neutron irradiation, mass inject, anvil collision craft</li><li><strong>System recipes</strong>: multiblock conversion, mob transform with item, multiple-to-one smithing, frost smithing, charger/discharger, energy weapon make</li></ul><p>Each recipe type includes JSON structure details and practical examples.</p><h4 id="_3-kubejs-integration" tabindex="-1">3. <a href="./kubejs/">KubeJS Integration</a> <a class="header-anchor" href="#_3-kubejs-integration" aria-label="Permalink to “3. KubeJS Integration”">​</a></h4><p>Provides complete integration guidance for AnvilCraft with KubeJS scripts, including:</p><ul><li>Scripted implementations for all supported recipe schemas</li><li>KubeJS-style chain builder APIs</li><li>Utility methods and constructor variants</li><li>Practical examples and integration notes</li></ul><h4 id="_4-anvillib-library" tabindex="-1">4. <a href="./anvillib/">AnvilLib Library</a> <a class="header-anchor" href="#_4-anvillib-library" aria-label="Permalink to “4. AnvilLib Library”">​</a></h4><p>Complete documentation for all AnvilLib modules:</p><ul><li><strong>Config</strong>: Annotation-based configuration system</li><li><strong>Integration</strong>: Mod compatibility integration framework</li><li><strong>Network</strong>: Automatic packet registration</li><li><strong>Recipe</strong>: In-world recipe system</li><li><strong>Moveable Entity Block</strong>: Piston-movable block entities</li><li><strong>Registrum</strong>: Fluent chain-style registration API</li></ul><hr><p>Whether you want to build feature-rich addon mods or customize gameplay through datapacks and scripts, this documentation provides the guidance and technical references you need.</p>',20)])])}const h=t(o,[["render",r]]);export{u as __pageData,h as default};
